```class Solution {
    public int racecar(int target) {
        int[] dp = new int[target + 1];
        Arrays.fill(dp, target + 1);
        dp[0] = 0;
        for (int i = 0; i <= target; i++) {
            if (i + (1 << (dp[i] - 1)) <= target) {
                dp[i + (1 << (dp[i] - 1))] = dp[i] + 1;
            }
            if (i > 0 && dp[i - 1] + 2 < dp[i]) {
                dp[i - 1] = dp[i] + 1;
            }
        }
        return dp[target];
    }
}```
